<div class="row g-4"><div class="col-lg-8"><div class="card"><div class="card-body"><h2 class="h5">1. Dirección de entrega</h2><?php foreach($dirs as$d):?><label class="border rounded p-3 d-block mb-2"><input type="radio" form="confirmar" name="direccion_id" value="<?=$d['id']?>" <?=$d['predeterminada']?'checked':''?> required> <strong><?=atenea_e(etiquetaDireccion($d))?></strong><span class="d-block ms-4"><?=atenea_e($d['receptor'].' · '.$d['telefono'])?></span><small class="d-block ms-4 text-muted"><?=atenea_e($d['direccion_detallada'].', '.$d['municipio'].', '.$d['departamento'])?></small></label><?php endforeach;?><?php if(!$dirs):?><div class="alert alert-info">Crea una dirección sin abandonar el checkout.</div><?php endif;?><details class="mt-3"><summary class="btn btn-outline-primary">Crear nueva dirección</summary><form method="post" action="<?=atenea_url('src/direcciones/guardar.php')?>" class="row g-2 mt-2"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="checkout" value="1"><div class="col-md-6"><select class="form-select" name="etiqueta"><option value="casa">Casa</option><option value="oficina">Oficina</option><option value="otra">Otra</option></select></div><div class="col-md-6"><input class="form-control" name="etiqueta_personalizada" maxlength="60" placeholder="Etiqueta si es Otra"></div><div class="col-md-6"><input class="form-control" name="receptor" maxlength="160" placeholder="Receptor" required></div><div class="col-md-6"><input class="form-control" name="telefono" maxlength="30" placeholder="Teléfono" required></div><div class="col-md-4"><select class="form-select" id="checkoutDepartamento" name="departamento_id" required><option value="">Departamento</option><?php foreach($deps as$d):?><option value="<?=$d['id']?>"><?=atenea_e($d['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-4"><select class="form-select" id="checkoutMunicipio" name="municipio_id" required disabled><option value="">Municipio</option></select></div><div class="col-md-4"><select class="form-select" id="checkoutDistrito" name="distrito_id" disabled><option value="">Distrito (si aplica)</option></select></div><div class="col-12"><textarea class="form-control" name="direccion_detallada" maxlength="500" placeholder="Dirección detallada" required></textarea></div><div class="col-12"><textarea class="form-control" name="referencias" maxlength="500" placeholder="Referencias"></textarea></div><div class="col-12"><button class="btn btn-primary">Guardar y volver</button></div></form></details></div></div></div>
<div class="col-lg-4"><div class="card"><div class="card-body"><h2 class="h5">2. Confirmación final</h2><p><?=$r['cantidad']?> producto(s)</p><div class="d-flex justify-content-between"><span>Subtotal</span><span>$<?=centavosDinero($r['subtotal'])?></span></div><div class="d-flex justify-content-between"><span>Descuento</span><span>-$<?=centavosDinero($r['descuento'])?></span></div><div class="d-flex justify-content-between"><span>Envío + impuestos</span><span>$<?=centavosDinero($r['envio']+$r['impuesto'])?></span></div><hr><div class="d-flex justify-content-between h5"><span>Total</span><span>$<?=centavosDinero($r['total'])?></span></div><form id="confirmar" method="post" action="<?=atenea_url('src/pagos/crear-checkout.php')?>"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="checkout_key" value="<?=$key?>"><label class="form-check mb-3"><input class="form-check-input" type="checkbox" name="confirmar_direccion" value="1" required><span class="form-check-label">Confirmo que la dirección seleccionada es correcta.</span></label><button class="btn btn-primary w-100" <?=$dirs?'':'disabled'?>>Ir al pago seguro</button></form></div></div></div></div><script>(function(){const d=document.getElementById('checkoutDepartamento'),m=document.getElementById('checkoutMunicipio'),i=document.getElementById('checkoutDistrito');async function fill(el,t,p){el.innerHTML='<option value="">Selecciona</option>';el.disabled=!p;if(!p)return;const r=await fetch('<?=atenea_url('src/api/ubicaciones.php')?>?tipo='+t+'&padre='+encodeURIComponent(p),{credentials:'same-origin',headers:{Accept:'application/json'}});const payload=await r.json();for(const v of (payload.data||[])){const o=document.createElement('option');o.value=v.id;o.textContent=v.nombre;el.appendChild(o);}}d?.addEventListener('change',async()=>{await fill(m,'municipios',d.value);await fill(i,'distritos','');});m?.addEventListener('change',()=>fill(i,'distritos',m.value));})();</script><?php portalEstudiantePie();
